    fetch(&quot;/api/user&quot;).then((r) =&gt; r.json()),
    fetch(&quot;/api/posts&quot;).then((r) =&gt; r.json()),
    fetch(&quot;/api/analytics&quot;).then((r) =&gt; r.json()),
