  return (
    &lt;div&gt;
      &lt;h1&gt;Welcome {user.name}&lt;/h1&gt;
      &lt;PostList posts={posts} /&gt;
      &lt;AnalyticsChart data={analytics} /&gt;
    &lt;/div&gt;
  );
}


