JSX cho phép nest các elements:
// to write JSX on multiple lines, wrap in parentheses: ()
const greeting = (
  // div is the parent element
  &lt;div&gt;
    {/* h1 and p are child elements */}
    &lt;h1&gt;Hello!&lt;/h1&gt;
    &lt;p&gt;Welcome to React&lt;/p&gt;
  &lt;/div&gt;
);
